INSERT INTO transcripts (id, interaction_id, full_text, overall_confidence) VALUES
  ('e0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', 'Agent: Good morning, how can I help you today?\nCustomer: Hi, I need help with my account.\nAgent: Sure, I can help with that. What seems to be the issue?\nCustomer: I cannot log in.\nAgent: Let me reset your password for you.\nCustomer: Thank you so much!', 0.82),
  ('e0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000002', 'Agent: Hello, welcome to support.\nCustomer: I want a refund for my last purchase.\nAgent: I understand. Can you provide the order number?\nCustomer: It is order 45892.\nAgent: I see the order. Let me process that refund for you right away.\nCustomer: Great, how long will it take?\nAgent: You should see it within 5 business days.\nCustomer: Okay, thanks.', 0.95),
  ('e0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000003', 'Agent: Thank you for calling, how may I assist you?\nCustomer: Your service has been terrible lately!\nAgent: I am really sorry to hear that. Can you tell me what happened?\nCustomer: My internet has been down for three days!\nAgent: That is unacceptable. Let me escalate this immediately.\nCustomer: Please do. This is ruining my work.', 0.95),
  ('e0000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000004', 'Agent: Hi there, what can I do for you?\nCustomer: I need to update my billing address.\nAgent: Of course. What is the new address?\nCustomer: 123 Nile Street, Cairo.\nAgent: Updated! Anything else?\nCustomer: No, that is all. Thank you.', 0.9),
  ('e0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000005', 'Agent: Welcome to support, how can I help?\nCustomer: I am scared my account has been hacked.\nAgent: I understand your concern. Let me check the recent activity on your account.\nCustomer: Please hurry, I see charges I did not make.\nAgent: I have secured your account and reversed the unauthorized charges.\nCustomer: Oh thank goodness. Thank you so much.', 0.92),
  ('e0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000006', 'Agent: Good afternoon! How can I assist you today?\nCustomer: I have a question about my subscription plan.\nAgent: Happy to help! Which plan are you on?\nCustomer: The premium plan, but I want to downgrade.\nAgent: I can process that for you. The change will take effect next billing cycle.\nCustomer: Perfect, thanks for the quick help.', 0.86),
  ('e0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000007', 'Agent: Hello, thank you for reaching out.\nCustomer: I am having trouble with the mobile app.\nAgent: I am sorry about that. What exactly is happening?\nCustomer: It keeps crashing when I open it.\nAgent: Try clearing the cache and reinstalling. I will also report this to our tech team.\nCustomer: Okay, I will try that.', 0.94),
  ('e0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000008', 'Agent: Hi, how can I help you?\nCustomer: I am really upset about the service I received last time.\nAgent: I sincerely apologize. What happened?\nCustomer: The agent was rude and did not solve my problem.\nAgent: That is not acceptable. I will escalate this and personally ensure your issue is resolved today.\nCustomer: I appreciate that.', 0.84),
  ('e0000000-0000-0000-0000-000000000009', 'd0000000-0000-0000-0000-000000000009', 'Agent: Good morning, support team here.\nCustomer: Can you help me set up two-factor authentication?\nAgent: Absolutely! Go to Settings, then Security, then enable 2FA.\nCustomer: Got it, what app should I use?\nAgent: Google Authenticator or Authy both work great.\nCustomer: Done! Thanks for walking me through it.', 0.89),
  ('e0000000-0000-0000-0000-000000000010', 'd0000000-0000-0000-0000-000000000010', 'Agent: Thank you for calling. How may I help?\nCustomer: I want to cancel my subscription.\nAgent: I am sorry to hear that. May I ask why?\nCustomer: It is too expensive for what I get.\nAgent: I understand. Would you be interested in our discounted plan at 40% off?\nCustomer: Hmm, that sounds interesting. Tell me more.\nAgent: It includes all core features at a reduced price.\nCustomer: Okay, switch me to that plan instead.', 0.86),
  ('e0000000-0000-0000-0000-000000000011', 'd0000000-0000-0000-0000-000000000011', 'Agent: Good morning, how can I help you today?\nCustomer: Hi, I need help with my account.\nAgent: Sure, I can help with that. What seems to be the issue?\nCustomer: I cannot log in.\nAgent: Let me reset your password for you.\nCustomer: Thank you so much!', 0.98),
