  ('12000000-0000-0000-0000-000000000141', 'd0000000-0000-0000-0000-000000000022', 'e0000000-0000-0000-0000-000000000022', 'agent', 'b0000000-0000-0000-0000-000000000010', 6, 19.2, 21.2, 'You should see it within 5 business days.', 'neutral', 0.72),
  ('12000000-0000-0000-0000-000000000142', 'd0000000-0000-0000-0000-000000000022', 'e0000000-0000-0000-0000-000000000022', 'customer', NULL, 7, 22.3, 24.2, 'Okay, thanks.', 'happy', 0.71),
  ('12000000-0000-0000-0000-000000000143', 'd0000000-0000-0000-0000-000000000023', 'e0000000-0000-0000-0000-000000000023', 'agent', 'b0000000-0000-0000-0000-000000000007', 0, 0.0, 2.1, 'Thank you for calling, how may I assist you?', 'neutral', 0.73),
  ('12000000-0000-0000-0000-000000000144', 'd0000000-0000-0000-0000-000000000023', 'e0000000-0000-0000-0000-000000000023', 'customer', NULL, 1, 3.3, 6.3, 'Your service has been terrible lately!', 'angry', 0.91),
  ('12000000-0000-0000-0000-000000000145', 'd0000000-0000-0000-0000-000000000023', 'e0000000-0000-0000-0000-000000000023', 'agent', 'b0000000-0000-0000-0000-000000000007', 2, 6.7, 8.8, 'I am really sorry to hear that. Can you tell me what happened?', 'empathetic', 0.7),
  ('12000000-0000-0000-0000-000000000146', 'd0000000-0000-0000-0000-000000000023', 'e0000000-0000-0000-0000-000000000023', 'customer', NULL, 3, 9.3, 10.9, 'My internet has been down for three days!', 'angry', 0.9),
  ('12000000-0000-0000-0000-000000000147', 'd0000000-0000-0000-0000-000000000023', 'e0000000-0000-0000-0000-000000000023', 'agent', 'b0000000-0000-0000-0000-000000000007', 4, 12.2, 16.0, 'That is unacceptable. Let me escalate this immediately.', 'empathetic', 0.79),
  ('12000000-0000-0000-0000-000000000148', 'd0000000-0000-0000-0000-000000000023', 'e0000000-0000-0000-0000-000000000023', 'customer', NULL, 5, 16.7, 19.2, 'Please do. This is ruining my work.', 'frustrated', 0.74),
  ('12000000-0000-0000-0000-000000000149', 'd0000000-0000-0000-0000-000000000024', 'e0000000-0000-0000-0000-000000000024', 'agent', 'b0000000-0000-0000-0000-000000000008', 0, 0.0, 3.2, 'Hi there, what can I do for you?', 'neutral', 0.74),
  ('12000000-0000-0000-0000-000000000150', 'd0000000-0000-0000-0000-000000000024', 'e0000000-0000-0000-0000-000000000024', 'customer', NULL, 1, 3.5, 6.9, 'I need to update my billing address.', 'neutral', 0.8),
  ('12000000-0000-0000-0000-000000000151', 'd0000000-0000-0000-0000-000000000024', 'e0000000-0000-0000-0000-000000000024', 'agent', 'b0000000-0000-0000-0000-000000000008', 2, 8.0, 11.8, 'Of course. What is the new address?', 'neutral', 0.71),
  ('12000000-0000-0000-0000-000000000152', 'd0000000-0000-0000-0000-000000000024', 'e0000000-0000-0000-0000-000000000024', 'customer', NULL, 3, 12.8, 15.9, '123 Nile Street, Cairo.', 'neutral', 0.81),
  ('12000000-0000-0000-0000-000000000153', 'd0000000-0000-0000-0000-000000000024', 'e0000000-0000-0000-0000-000000000024', 'agent', 'b0000000-0000-0000-0000-000000000008', 4, 16.3, 18.7, 'Updated! Anything else?', 'neutral', 0.76),
  ('12000000-0000-0000-0000-000000000154', 'd0000000-0000-0000-0000-000000000024', 'e0000000-0000-0000-0000-000000000024', 'customer', NULL, 5, 19.8, 23.4, 'No, that is all. Thank you.', 'happy', 0.76),
  ('12000000-0000-0000-0000-000000000155', 'd0000000-0000-0000-0000-000000000025', 'e0000000-0000-0000-0000-000000000025', 'agent', 'b0000000-0000-0000-0000-000000000009', 0, 0.0, 3.6, 'Welcome to support, how can I help?', 'neutral', 0.65),
  ('12000000-0000-0000-0000-000000000156', 'd0000000-0000-0000-0000-000000000025', 'e0000000-0000-0000-0000-000000000025', 'customer', NULL, 1, 4.9, 7.6, 'I am scared my account has been hacked.', 'fearful', 0.67),
  ('12000000-0000-0000-0000-000000000157', 'd0000000-0000-0000-0000-000000000025', 'e0000000-0000-0000-0000-000000000025', 'agent', 'b0000000-0000-0000-0000-000000000009', 2, 8.6, 11.3, 'I understand your concern. Let me check the recent activity on your account.', 'empathetic', 0.79),
  ('12000000-0000-0000-0000-000000000158', 'd0000000-0000-0000-0000-000000000025', 'e0000000-0000-0000-0000-000000000025', 'customer', NULL, 3, 11.9, 13.7, 'Please hurry, I see charges I did not make.', 'fearful', 0.74),
  ('12000000-0000-0000-0000-000000000159', 'd0000000-0000-0000-0000-000000000025', 'e0000000-0000-0000-0000-000000000025', 'agent', 'b0000000-0000-0000-0000-000000000009', 4, 14.6, 16.2, 'I have secured your account and reversed the unauthorized charges.', 'empathetic', 0.85),
  ('12000000-0000-0000-0000-000000000160', 'd0000000-0000-0000-0000-000000000025', 'e0000000-0000-0000-0000-000000000025', 'customer', NULL, 5, 17.4, 19.7, 'Oh thank goodness. Thank you so much.', 'happy', 0.65),
  ('12000000-0000-0000-0000-000000000161', 'd0000000-0000-0000-0000-000000000026', 'e0000000-0000-0000-0000-000000000026', 'agent', 'b0000000-0000-0000-0000-000000000010', 0, 0.0, 2.2, 'Good afternoon! How can I assist you today?', 'happy', 0.92),
  ('12000000-0000-0000-0000-000000000162', 'd0000000-0000-0000-0000-000000000026', 'e0000000-0000-0000-0000-000000000026', 'customer', NULL, 1, 3.7, 5.8, 'I have a question about my subscription plan.', 'neutral', 0.83),
  ('12000000-0000-0000-0000-000000000163', 'd0000000-0000-0000-0000-000000000026', 'e0000000-0000-0000-0000-000000000026', 'agent', 'b0000000-0000-0000-0000-000000000010', 2, 7.2, 10.0, 'Happy to help! Which plan are you on?', 'happy', 0.93),
  ('12000000-0000-0000-0000-000000000164', 'd0000000-0000-0000-0000-000000000026', 'e0000000-0000-0000-0000-000000000026', 'customer', NULL, 3, 10.6, 14.1, 'The premium plan, but I want to downgrade.', 'neutral', 0.78),
  ('12000000-0000-0000-0000-000000000165', 'd0000000-0000-0000-0000-000000000026', 'e0000000-0000-0000-0000-000000000026', 'agent', 'b0000000-0000-0000-0000-000000000010', 4, 15.0, 18.6, 'I can process that for you. The change will take effect next billing cycle.', 'neutral', 0.74),
  ('12000000-0000-0000-0000-000000000166', 'd0000000-0000-0000-0000-000000000026', 'e0000000-0000-0000-0000-000000000026', 'customer', NULL, 5, 19.3, 22.3, 'Perfect, thanks for the quick help.', 'happy', 0.97),
  ('12000000-0000-0000-0000-000000000167', 'd0000000-0000-0000-0000-000000000027', 'e0000000-0000-0000-0000-000000000027', 'agent', 'b0000000-0000-0000-0000-000000000007', 0, 0.0, 2.1, 'Hello, thank you for reaching out.', 'neutral', 0.77),
  ('12000000-0000-0000-0000-000000000168', 'd0000000-0000-0000-0000-000000000027', 'e0000000-0000-0000-0000-000000000027', 'customer', NULL, 1, 3.4, 5.9, 'I am having trouble with the mobile app.', 'frustrated', 0.75),
  ('12000000-0000-0000-0000-000000000169', 'd0000000-0000-0000-0000-000000000027', 'e0000000-0000-0000-0000-000000000027', 'agent', 'b0000000-0000-0000-0000-000000000007', 2, 7.3, 9.8, 'I am sorry about that. What exactly is happening?', 'empathetic', 0.97),
  ('12000000-0000-0000-0000-000000000170', 'd0000000-0000-0000-0000-000000000027', 'e0000000-0000-0000-0000-000000000027', 'customer', NULL, 3, 10.9, 12.8, 'It keeps crashing when I open it.', 'frustrated', 0.96),
  ('12000000-0000-0000-0000-000000000171', 'd0000000-0000-0000-0000-000000000027', 'e0000000-0000-0000-0000-000000000027', 'agent', 'b0000000-0000-0000-0000-000000000007', 4, 14.3, 16.6, 'Try clearing the cache and reinstalling. I will also report this to our tech team.', 'neutral', 0.68),
  ('12000000-0000-0000-0000-000000000172', 'd0000000-0000-0000-0000-000000000027', 'e0000000-0000-0000-0000-000000000027', 'customer', NULL, 5, 17.0, 20.8, 'Okay, I will try that.', 'neutral', 0.65),
  ('12000000-0000-0000-0000-000000000173', 'd0000000-0000-0000-0000-000000000028', 'e0000000-0000-0000-0000-000000000028', 'agent', 'b0000000-0000-0000-0000-000000000008', 0, 0.0, 3.6, 'Hi, how can I help you?', 'neutral', 0.92),
  ('12000000-0000-0000-0000-000000000174', 'd0000000-0000-0000-0000-000000000028', 'e0000000-0000-0000-0000-000000000028', 'customer', NULL, 1, 4.9, 7.4, 'I am really upset about the service I received last time.', 'angry', 0.75),
  ('12000000-0000-0000-0000-000000000175', 'd0000000-0000-0000-0000-000000000028', 'e0000000-0000-0000-0000-000000000028', 'agent', 'b0000000-0000-0000-0000-000000000008', 2, 8.6, 12.3, 'I sincerely apologize. What happened?', 'empathetic', 0.66),
  ('12000000-0000-0000-0000-000000000176', 'd0000000-0000-0000-0000-000000000028', 'e0000000-0000-0000-0000-000000000028', 'customer', NULL, 3, 13.4, 17.2, 'The agent was rude and did not solve my problem.', 'angry', 0.97),
  ('12000000-0000-0000-0000-000000000177', 'd0000000-0000-0000-0000-000000000028', 'e0000000-0000-0000-0000-000000000028', 'agent', 'b0000000-0000-0000-0000-000000000008', 4, 18.0, 19.7, 'That is not acceptable. I will escalate this and personally ensure your issue is resolved today.', 'empathetic', 0.85),
  ('12000000-0000-0000-0000-000000000178', 'd0000000-0000-0000-0000-000000000028', 'e0000000-0000-0000-0000-000000000028', 'customer', NULL, 5, 20.5, 23.7, 'I appreciate that.', 'neutral', 0.94),
  ('12000000-0000-0000-0000-000000000179', 'd0000000-0000-0000-0000-000000000029', 'e0000000-0000-0000-0000-000000000029', 'agent', 'b0000000-0000-0000-0000-000000000009', 0, 0.0, 3.0, 'Good morning, support team here.', 'neutral', 0.77),
  ('12000000-0000-0000-0000-000000000180', 'd0000000-0000-0000-0000-000000000029', 'e0000000-0000-0000-0000-000000000029', 'customer', NULL, 1, 4.1, 6.8, 'Can you help me set up two-factor authentication?', 'neutral', 0.84),
  ('12000000-0000-0000-0000-000000000181', 'd0000000-0000-0000-0000-000000000029', 'e0000000-0000-0000-0000-000000000029', 'agent', 'b0000000-0000-0000-0000-000000000009', 2, 7.4, 10.5, 'Absolutely! Go to Settings, then Security, then enable 2FA.', 'happy', 0.8),
  ('12000000-0000-0000-0000-000000000182', 'd0000000-0000-0000-0000-000000000029', 'e0000000-0000-0000-0000-000000000029', 'customer', NULL, 3, 11.9, 14.6, 'Got it, what app should I use?', 'neutral', 0.74),
  ('12000000-0000-0000-0000-000000000183', 'd0000000-0000-0000-0000-000000000029', 'e0000000-0000-0000-0000-000000000029', 'agent', 'b0000000-0000-0000-0000-000000000009', 4, 15.0, 18.9, 'Google Authenticator or Authy both work great.', 'neutral', 0.97),
  ('12000000-0000-0000-0000-000000000184', 'd0000000-0000-0000-0000-000000000029', 'e0000000-0000-0000-0000-000000000029', 'customer', NULL, 5, 19.6, 23.5, 'Done! Thanks for walking me through it.', 'happy', 0.87),
  ('12000000-0000-0000-0000-000000000185', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'agent', 'b0000000-0000-0000-0000-000000000010', 0, 0.0, 3.6, 'Thank you for calling. How may I help?', 'neutral', 0.78),
  ('12000000-0000-0000-0000-000000000186', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'customer', NULL, 1, 3.9, 7.6, 'I want to cancel my subscription.', 'sad', 0.9),
  ('12000000-0000-0000-0000-000000000187', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'agent', 'b0000000-0000-0000-0000-000000000010', 2, 9.0, 12.4, 'I am sorry to hear that. May I ask why?', 'empathetic', 0.92),
  ('12000000-0000-0000-0000-000000000188', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'customer', NULL, 3, 13.6, 15.7, 'It is too expensive for what I get.', 'frustrated', 0.91),
  ('12000000-0000-0000-0000-000000000189', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'agent', 'b0000000-0000-0000-0000-000000000010', 4, 16.2, 18.3, 'I understand. Would you be interested in our discounted plan at 40% off?', 'neutral', 0.89),
  ('12000000-0000-0000-0000-000000000190', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'customer', NULL, 5, 19.4, 21.2, 'Hmm, that sounds interesting. Tell me more.', 'neutral', 0.68),
  ('12000000-0000-0000-0000-000000000191', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'agent', 'b0000000-0000-0000-0000-000000000010', 6, 22.3, 23.9, 'It includes all core features at a reduced price.', 'neutral', 0.9),
  ('12000000-0000-0000-0000-000000000192', 'd0000000-0000-0000-0000-000000000030', 'e0000000-0000-0000-0000-000000000030', 'customer', NULL, 7, 24.2, 26.6, 'Okay, switch me to that plan instead.', 'happy', 0.69);
